<template>
    <transition name="modal">
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block dialog">
                <div class="modal-dialog">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full">
                            <h4 class="modal-title">{{ $t("PaymentHistory") }}</h4>
                            <button type="button" class="close" v-on:click="closePaymentHistroy">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <div class="card-body float-left p-0 col-12 float-left">
                                <div class="row">
                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>{{ $t("BillNumber") }}:
                                                {{ paymentHistoryData.MainInvoiceNumber }}</label>
                                        </div>
                                    </div>

                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>{{ $t("IssueDate") }}:
                                                {{
                                                    formatDateMonth(
                                                        paymentHistoryData.MainInvoiceIssueDate
                                                    )
                                                }}</label>
                                        </div>
                                    </div>
                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>{{ $t("DueDate") }}:
                                                {{
                                                    formatDateMonth(
                                                        paymentHistoryData.MainInvoiceDueDate
                                                    )
                                                }}</label>
                                        </div>
                                    </div>
                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>Advance (PKR):
                                                <span v-if="
                                                    paymentHistoryData.MainInvocieAdvacncedRecived ==
                                                    0
                                                ">{{ $n(0.00 , 'currency', $getLocaleByCurrency(CurrencyCode)) }}</span>
                                                <span v-if="
                                                    paymentHistoryData.MainInvocieAdvacncedRecived !=
                                                    0
                                                ">{{ $n(paymentHistoryData.MainInvocieAdvacncedRecived , 'currency', $getLocaleByCurrency(CurrencyCode)) }}</span>
                                            </label>
                                        </div>
                                    </div>
                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>Discount Flat Rate (PKR):
                                                <span v-if="
                                                    paymentHistoryData.MainInvoiceFlatDiscount == 0
                                                ">{{ $n(0.00 , 'currency', $getLocaleByCurrency(CurrencyCode)) }}</span>
                                                <span v-if="
                                                    paymentHistoryData.MainInvoiceFlatDiscount != 0
                                                "> {{ $n(paymentHistoryData.MainInvoiceFlatDiscount , 'currency', $getLocaleByCurrency(CurrencyCode)) }}</span>
                                            </label>
                                        </div>
                                    </div>
                                    <div class="col-md-4 col-lg-4">
                                        <div class="form-group">
                                            <label>Amount (PKR):
                                                <span
                                                    v-if="!paymentHistoryData || paymentHistoryData.MainInvocieNetAmount == 0">0.00</span>
                                                <span v-else>{{ $n(formattedAmount , 'currency', $getLocaleByCurrency(CurrencyCode)) }}</span>
                                            </label>
                                        </div>
                                    </div>
                                </div>

                                <div class="listing">
                                    <div class="table-responsive table-fix-header">
                                        <table id="maintable" class="table-sorting table table-bordered my-0">
                                            <thead class="thead-light">
                                                <tr>
                                                    <th width="30%">
                                                        <span>{{ $t("Notes") }}</span>
                                                    </th>
                                                    <th width="20%">
                                                        <span>{{ $t("PaymentDate") }}</span>
                                                    </th>
                                                    <th width="20%" class="text-right">
                                                        <span>{{ $t("Amount") }} ({{
                                                            paymentHistoryData.MainInvoiceCompanyIsoCode
                                                        }})</span>
                                                    </th>
                                                    <th width="30%" class="text-center">
                                                        <span>{{ $t("Action") }}</span>
                                                    </th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                <tr v-if="!paymentList || paymentList.length == 0">
                                                    <td colspan="4" class="text-center text-danger">
                                                        {{ $t("NoPaymentFound") }}
                                                    </td>
                                                </tr>
                                                <!-- Check if payment list is available -->
                                                <tr v-else-if="
                                                    paymentList &&
                                                    paymentList.length > 0 &&
                                                    totalPayments < MainInvocieNetAmount
                                                " v-for="(childInvoice, index) in paymentList" :key="index"
                                                    class="myrow">
                                                    <td>
                                                        <span>{{ childInvoice.MainNote }}</span>
                                                    </td>
                                                    <td>
                                                        <span>{{
                                                            formatDateMonth(childInvoice.PaymentDate)
                                                        }}</span>
                                                    </td>
                                                    <td class="text-right">
                                                        <span>{{
                                                            formatAmount(childInvoice.Amount)
                                                        }}</span>
                                                    </td>
                                                    <td class="text-center">
                                                        <!-- <a v-if="userType !== 'CL'" href="javascript:;" class="pay_hist_edit EditAnchor" title="Edit">
                                                                <i class="fa fa-pencil text-success action-icon"></i>
                                                                </a>
                                                                <a v-if="userType !== 'CL'" href="javascript:;" class="pay_hist_update UpdateAnchor" style="display: none" title="Update">
                                                                <i class="fa fa-clock-o text-secondary action-icon"></i>
                                                                </a>
                                                                <a v-if="userType !== 'CL'" href="javascript:;" class="pay_hist_cancel UpdateCancelAnchor" style="display: none" title="Cancel">
                                                                <i class="fa fa-trash text-danger action-icon"></i>
                                                                </a> -->
                                                    </td>
                                                </tr>
                                            </tbody>
                                            <tfoot>
                                                <tr>
                                                    <td></td>
                                                    <td class="text-right">
                                                        {{ $t("NetAmountPaid") }}:
                                                    </td>
                                                    <td class="text-right font-weight-bold">
                                                             {{ $n(formatAmount(totalPaid) , 'currency', $getLocaleByCurrency(CurrencyCode)) }}
                                                    </td>
                                                    <td></td>
                                                </tr>
                                                <tr>
                                                    <td></td>
                                                    <td class="text-right">
                                                        {{ $t("OutStandingAmount") }}
                                                    </td>
                                                    <td class="text-right font-weight-bold">
                                                        <span :style="{
                                                            color:
                                                                outstandingAmount < 0 ? 'green' : 'red',
                                                        }">
                                                     {{ $n(formatAmount(outstandingAmount) , 'currency', $getLocaleByCurrency(CurrencyCode)) }} 
                                                        </span>
                                                    </td>
                                                    <td></td>
                                                </tr>
                                            </tfoot>
                                        </table>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div class="modal-footer">
                            <div class="col-lg-6 text-right p-0">
                                <a href="javascript:;" class="btn btn-danger formbtn text-white"
                                    v-on:click="closePaymentHistroy"><em class="fa fa-close pr-2"></em>{{ $t("Cancel")
                                    }}</a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </transition>
</template>
<script>
import DataService from '../../services/DataService';
export default {

    props: {
        BillId: {
            type: Number,
        },

    },
    computed: {
        formattedAmount() {
            return this.paymentHistoryData.MainInvocieNetAmount.toFixed(2);
        }
        ,
        totalPaid() {
            return this.paymentList.reduce((sum, payment) => sum + payment.Amount, 0);
        },
        outstandingAmount() {
            return this.MainInvocieNetAmount - this.totalPaid;
        },

    },
    data() {
        return {
            paymentHistoryData: [],
            paymentList: [],
            MainInvocieNetAmount: 0,
            totalPayments: 0,
            CurrencyCode: 'PKR'
        }
    },
    created() {
        var vm =this;
        this.openPaymentHistory();
        vm.CurrencyCode = vm.GetUserInfo.Currency.replace(/[()]/g, '');

    },
    methods: {
        closePaymentHistroy() {
            this.$parent.isPaymentHistory = false
        },
        async openPaymentHistory() {
            debugger;
            const vm = this;
            const params = `invoiceId=${this.BillId}`;
            try {
                const response = await DataService.GetPaymentHistoryPopUp(params);
                if (response.data) {
                    vm.paymentHistoryData = response.data;
                    vm.paymentList = response.data.PaymentLists;
                    vm.MainInvocieNetAmount = response.data.MainInvocieNetAmount;
                    vm.totalPayments = vm.paymentList.reduce((sum, payment) => sum + payment.Amount, 0);
                } else {
                    vm.paymentHistoryData = [];
                }
            } catch (error) {
                console.error('Error fetching payment history:', error);

            }
        },
        formatDateMonth(dateTimeString) {
            if (!dateTimeString) return "";
            //debugger;
            const [datePart, timePart] = dateTimeString.split(" "); // ['06-11-2024', '06:00:09']
            const [day, month, year] = datePart.split("-"); // ['06', '11', '2024']
            const date = new Date(`${year}-${month}-${day}T00:00:00`);
            const months = [
                "Jan",
                "Feb",
                "Mar",
                "Apr",
                "May",
                "Jun",
                "Jul",
                "Aug",
                "Sep",
                "Oct",
                "Nov",
                "Dec",
            ];
            const formattedDay = String(date.getDate()).padStart(2, "0");
            const formattedMonth = months[date.getMonth()];
            const formattedYear = date.getFullYear();
            return `${formattedMonth}-${formattedDay}-${formattedYear}`;
        },
        formatAmount(amount) {
            debugger;
            return amount.toFixed(2);

        },
    },
}
</script>
<style lang="">

</style>